using System;
using System.Reflection;
using System.Linq;

class Program
{
    static void Main()
    {
        var dlls = new[]
        {
            "/home/runner/.nuget/packages/microsoft.agents.ai/1.0.0/lib/net9.0/Microsoft.Agents.AI.dll",
            "/home/runner/.nuget/packages/microsoft.extensions.ai.abstractions/9.10.2/lib/net9.0/Microsoft.Extensions.AI.Abstractions.dll",
            "/home/runner/.nuget/packages/microsoft.extensions.ai/9.10.2/lib/net9.0/Microsoft.Extensions.AI.dll",
            "/home/runner/.nuget/packages/microsoft.extensions.ai.openai/10.3.0/lib/net9.0/Microsoft.Extensions.AI.OpenAI.dll",
        };

        foreach (var dll in dlls)
        {
            if (!System.IO.File.Exists(dll)) continue;

            Console.WriteLine($"\n{'='}{new string('=', 98)}\n");
            Console.WriteLine($"ASSEMBLY: {System.IO.Path.GetFileName(dll)}");
            Console.WriteLine(new string('=', 100));

            try
            {
                var asm = Assembly.LoadFrom(dll);
                var publicTypes = asm.GetTypes()
                    .Where(t => t.IsPublic && !t.Name.Contains("<") && !t.Name.StartsWith("__"))
                    .OrderBy(t => t.Namespace)
                    .ThenBy(t => t.Name)
                    .ToList();

                var byNamespace = publicTypes.GroupBy(t => t.Namespace ?? "Global");

                foreach (var ns in byNamespace)
                {
                    Console.WriteLine($"\n  Namespace: {ns.Key}");
                    foreach (var type in ns)
                    {
                        string kind = type.IsInterface ? "interface" : type.IsEnum ? "enum" : type.IsValueType ? "struct" : "class";
                        Console.WriteLine($"    [{kind:8}] {type.Name}");

                        // Show key methods for agent-related types
                        if (type.Name.Contains("Agent") || type.Name.Contains("Chat") || type.Name.Contains("Function") || 
                            type.Name.Contains("Tool") || type.Name.Contains("Message") || type.Name == "IChatClient")
                        {
                            var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
                                .Where(m => !m.IsSpecialName)
                                .Take(15)
                                .ToList();

                            var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
                                .Take(15)
                                .ToList();

                            if (methods.Any())
                            {
                                foreach (var method in methods)
                                {
                                    var parms = string.Join(", ", method.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name));
                                    Console.WriteLine($"              Method: {method.ReturnType.Name} {method.Name}({parms})");
                                }
                            }

                            if (props.Any())
                            {
                                foreach (var prop in props)
                                {
                                    Console.WriteLine($"              Prop: {prop.PropertyType.Name} {prop.Name}");
                                }
                            }
                        }
                    }
                }

                Console.WriteLine($"\n  Total public types: {publicTypes.Count}");
            }
            catch (Exception ex)
            {
                Console.WriteLine($"ERROR: {ex.Message}");
            }
        }
    }
}
